class Solution(object):
    def allPathsSourceTarget(self, graph):
        result = []
        def dfs(node, path):
            if node == len(graph) - 1:
                result.append(path)
                return
            for neighbor in graph[node]:
                dfs(neighbor, path + [neighbor])
        dfs(0, [0])
        return result
